        {"type":0,"content":"3/19/26 \\n\\nYesterday: Did some of the coding for routing and the bottom tab navigation. Ran into dependency issues while trying to run it through expo go. Couldn't figure out how to debug. \\n\\nToday: Made some breakthroughs on the debugging process. During the team meeting we decided to go with the older format of the app and work in android studio. \\n\\nTomorrow: Try to resolve merge conflicts, and get Chayton's working code distributed to the team. \\n\\nBlockers: Merge conflicts I have no idea how to resolve.","mentions":[],"mention_roles":[],"attachments":[],"embeds":[],"timestamp":"2026-03-20T03:23:48.061000+00:00","edited_timestamp":null,"flags":0,"components":[],"id":"1484391985702899783","channel_id":"1478078339632730223","author":{"id":"790404319957876789","username":"pervysagekip","avatar":"850df8641933da68e7dec607147c725a","discriminator":"0","public_flags":0,"flags":0,"banner":null,"accent_color":null,"global_name":"PervySageKip","avatar_decoration_data":null,"collectibles":null,"display_name_styles":null,"banner_color":null,"clan":null,"primary_guild":null},"pinned":false,"mention_everyone":false,"tts":false}
